const dlms_config = {dlmsBaseUrl: 'https://dlms-api.iotnp.com', npBaseUrl: 'https://api.nowpurchase.com'} || {};
const [searchValue, loadCallback, currentDataLength] = e.args;

if (window._furnaceDropdownDebounceTimer) {
    clearTimeout(window._furnaceDropdownDebounceTimer);
}

if (window._furnaceDropdownAbortController) {
    window._furnaceDropdownAbortController.abort();
}

window._furnaceDropdownAbortController = new AbortController();
const signal = window._furnaceDropdownAbortController.signal;

window._furnaceDropdownDebounceTimer = setTimeout(async () => {
    let savedToken = localStorage.getItem('tokenv2') || localStorage.getItem('nowpurchase_token');

    try {
        const res = await fetch(`${dlms_config.npBaseUrl}/api/dropdown/furnace/`, {
            method: 'GET',
            headers: {
                'accept': 'application/json',
                'Authorization': `Token ${savedToken}`
            },
            signal: signal
        });

        const response = await res.json();
        const items = Array.isArray(response) ? response : [];

        const filteredItems = items.filter(item => {
            const name = item.furnace_name || "";
            return name.toLowerCase().includes((searchValue || "").toLowerCase());
        });

        const uniqueMap = new Map();
        filteredItems.forEach(item => {
            const furnaceName = item.furnace_name || "Unnamed Furnace";
            const furnaceId = item.id;

            if (!uniqueMap.has(furnaceId)) {
                uniqueMap.set(furnaceId, {
                    value: furnaceName,
                    label: furnaceName,
                    data: {
                        id: item.id,
                        furnace_name: item.furnace_name || "",
                        capacity: item.capacity || 0,
                        furnace_tag_id: item.furnace_tag_id || ""
                    }
                });
            }
        });

        const preparedData = [...uniqueMap.values()]
            .slice(currentDataLength || 0, (currentDataLength || 0) + 20);

        if (typeof loadCallback === 'function') {
            loadCallback(preparedData);
        }

    } catch (err) {
        if (err.name === 'AbortError') {
            return;
        }
        if (typeof loadCallback === 'function') loadCallback([]);
    }

}, 300);

