const dlms_config = {dlmsBaseUrl: 'https://dlms-api.iotnp.com', npBaseUrl: 'https://api.nowpurchase.com'} || {};
 // 1. Resolve e if it`s a promise
  if (e instanceof Promise || (e && typeof e.then === "function")) {
    console.log("e is a promise, awaiting...");
    e = await e;
  }

  // 2. Safely access e.data
  if (!e || !e.data) {
    console.error("e or e.data is not available:", e);
    return;
  }

  // 3. Wait until both date and furnace__label are set (poll every 200ms, timeout 10s)
  const maxWait = 10000;
  const interval = 200;
  let waited = 0;

  while ((!e.data.date || !e.data.furnace__label) && waited < maxWait) {
    console.warn(`Waiting for date and furnace__label... (${waited}ms)`);
    await new Promise((resolve) => setTimeout(resolve, interval));
    waited += interval;
  }

  if (!e.data.date || !e.data.furnace__label) {
    console.error("Timed out waiting for date and furnace__label after 10s");
    return;
  }

  // 2. Debounce the API call
  if (window._serialNoDropdownDebounceTimer) {
    clearTimeout(window._serialNoDropdownDebounceTimer);
  }

  window._serialNoDropdownDebounceTimer = setTimeout(async () => {
    try {
      // 3. Get auth token from localStorage
      const savedToken = localStorage.getItem("dlms_auth_token");
      if (!savedToken) {
        console.error("No auth token found in localStorage (dlms_auth_token)");
        return;
      }

      // 4. Build created_at filter from e.data.date
      const dateValue =
        e.data.date instanceof Date ? e.data.date : new Date(e.data.date);

      // 6 AM of selected date
      const createdAtGte = new Date(
        dateValue.getFullYear(),
        dateValue.getMonth(),
        dateValue.getDate(),
        6, 0, 0
      ).toISOString();

      // 6 AM of next date
      const nextDay = new Date(
        dateValue.getFullYear(),
        dateValue.getMonth(),
        dateValue.getDate() + 1,
        6, 0, 0
      );
      const createdAtLte = nextDay.toISOString();

      const furnaceLabel = e.data.furnace__label;

      // 5. Build payload
      const payload = {
        fields: [
          "data.main.data.batch_id",
          "data.main.data.furnace__label",
          "data.main.data.date",
        ],
        filters: [
          { field: "data.main.data.furnace__label", value: furnaceLabel },
          { field: "meta.created_at", value: createdAtGte, operator: "gte" },
          { field: "meta.created_at", value: createdAtLte, operator: "lte" },
        ],
        status: "completed",
        limit: 20,
      };

      // 6. Make the API call
      const response = await fetch(
        `${dlms_config.dlmsBaseUrl}/api/v1/templates/heat_treatment_operational/dropdown/v2`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${savedToken}`,
          },
          body: JSON.stringify(payload),
        }
      );

      if (!response.ok) {
        console.error(
          `Dropdown API error: ${response.status} ${response.statusText}`
        );
        return;
      }

      const result = await response.json();

      // 7. Generate Batch ID: YYYY-MM-DD-FurnaceLabel/Count
      //    Month coded: A=Jan, B=Feb, C=Mar, ... L=Dec
      const monthCode = String.fromCharCode(65 + dateValue.getMonth()); // 65 = `A'
      const year = dateValue.getFullYear();
      const day = String(dateValue.getDate()).padStart(2, "0");

      // Count from API response + 1
      const existingCount = result.count || result.data?.length || 0;
      const newCount = existingCount + 1;

      const batchId = `${year}-${monthCode}-${day}-${furnaceLabel}/${newCount}`;
      console.log("Generated Batch ID:", batchId);

      // 8. Set the batch_id on the form
      e.data.batch_id = batchId;

    } catch (err) {
      console.error("Dropdown fetch failed:", err);
    }
  }, 300);

