const errors = {};

const hasValue = (val) => {
    return val !== null && val !== undefined && val !== '';
};

let hasAtLeastOnePair = false;

// Time/Temp pair validation
for (let i = 1; i <= 15; i++) {
    const tempKey = `temp_${i}`;
    const timeKey = `time_${i}`;

    const tempValue = formData[tempKey];
    const timeValue = formData[timeKey];

    if (hasValue(tempValue) && hasValue(timeValue)) {
        hasAtLeastOnePair = true;
    }

    if (hasValue(tempValue) && !hasValue(timeValue)) {
        errors[timeKey] = `Time ${i} is required`;
    }

    if (hasValue(timeValue) && !hasValue(tempValue)) {
        errors[tempKey] = `Temp ${i} is required`;
    }
}

if (!hasAtLeastOnePair) {
    errors['temp_1'] = 'At least one Temperature & Time pair is required';
    errors['time_1'] = 'At least one Temperature & Time pair is required';
}

// Casting group qty validation
for (let i = 1; i <= 10; i++) {
    const castingNameKey = `casting_group_${i}_name`;
    const qtyKey = `qty_${i}`;

    const castingNameValue = formData[castingNameKey];
    const qtyValue = formData[qtyKey];

    // If casting group exists, qty is required
    if (hasValue(castingNameValue) && !hasValue(qtyValue)) {
        errors[qtyKey] = `Qty is required for ${castingNameValue}`;
    }
}

return Object.keys(errors).length > 0 ? errors : undefined;

